/**
 * E2E: hooks.json wiring completeness
 *
 * Validates that every hook event in hooks.json has a matching entry-bundle
 * export, async/timeout config is sane for error-loop-sensitive handlers
 * (StopFailure, Stop), and the description field count-stamps match the
 * actual number of registered hooks. Originally added for CC 2.1.78's
 * StopFailure + --worktree fix; scope is now general wiring validation.
 */

import { describe, it, expect, beforeAll } from 'vitest';
import fs from 'node:fs';
import path from 'node:path';

interface Hook {
  type: string;
  command?: string;
  async?: boolean;
  timeout?: number;
  once?: boolean;
}

interface HookGroup {
  matcher?: string;
  hooks: Hook[];
}

interface HooksConfig {
  description: string;
  hooks: Record<string, HookGroup[]>;
}

describe('hooks.json wiring E2E', () => {
  let hooksConfig: HooksConfig;

  beforeAll(() => {
    const hooksPath = path.resolve(__dirname, '..', '..', '..', 'hooks.json');
    const content = fs.readFileSync(hooksPath, 'utf-8');
    hooksConfig = JSON.parse(content);
  });

  // ===========================================================================
  // StopFailure event wiring
  // ===========================================================================
  describe('StopFailure event (CC 2.1.78)', () => {
    it('StopFailure is registered in hooks.json', () => {
      expect(hooksConfig.hooks.StopFailure).toBeDefined();
      expect(Array.isArray(hooksConfig.hooks.StopFailure)).toBe(true);
      expect(hooksConfig.hooks.StopFailure.length).toBeGreaterThan(0);
    });

    it('StopFailure timeout is reasonable (5-30 seconds)', () => {
      const hooks = hooksConfig.hooks.StopFailure.flatMap(g => g.hooks ?? []);
      for (const hook of hooks) {
        if (typeof hook.timeout === 'number') {
          expect(hook.timeout).toBeGreaterThanOrEqual(5);
          expect(hook.timeout).toBeLessThanOrEqual(30);
        }
      }
    });

    it('StopFailure command routes to stop-failure-handler', () => {
      const hooks = hooksConfig.hooks.StopFailure.flatMap(g => g.hooks ?? []);
      const hasHandler = hooks.some(h =>
        typeof h.command === 'string' && h.command.includes('stop-failure-handler')
      );
      expect(hasHandler).toBe(true);
    });

    it('StopFailure is separate from Stop event (not dispatched together)', () => {
      const stopHooks = hooksConfig.hooks.Stop?.flatMap(g => g.hooks ?? []) ?? [];
      const stopFailureHooks = hooksConfig.hooks.StopFailure?.flatMap(g => g.hooks ?? []) ?? [];

      // StopFailure should NOT use the same dispatcher as Stop
      const stopCommands = stopHooks.map(h => h.command).filter(Boolean);
      const sfCommands = stopFailureHooks.map(h => h.command).filter(Boolean);

      // At least one command should differ (they're different handlers)
      // lifecycle/webhook-forwarder is a cross-cutting hook on all events — exclude from overlap check
      const overlap = sfCommands.filter(c => stopCommands.includes(c) && !c?.includes('webhook-forwarder'));
      expect(overlap.length).toBe(0);
    });
  });

  // ===========================================================================
  // WorktreeCreate / WorktreeRemove wiring
  // ===========================================================================
  describe('Worktree events (CC 2.1.78 --worktree fix)', () => {
    it('WorktreeCreate is registered in hooks.json', () => {
      expect(hooksConfig.hooks.WorktreeCreate).toBeDefined();
      expect(hooksConfig.hooks.WorktreeCreate.length).toBeGreaterThan(0);
    });

    it('WorktreeRemove is registered in hooks.json', () => {
      expect(hooksConfig.hooks.WorktreeRemove).toBeDefined();
      expect(hooksConfig.hooks.WorktreeRemove.length).toBeGreaterThan(0);
    });

    it('WorktreeCreate and WorktreeRemove use the same handler', () => {
      const createHooks = hooksConfig.hooks.WorktreeCreate.flatMap(g => g.hooks ?? []);
      const removeHooks = hooksConfig.hooks.WorktreeRemove.flatMap(g => g.hooks ?? []);

      const createCommands = createHooks.map(h => h.command).filter(Boolean);
      const removeCommands = removeHooks.map(h => h.command).filter(Boolean);

      // Both should route to worktree-lifecycle-logger
      expect(createCommands.some(c => c!.includes('worktree-lifecycle-logger'))).toBe(true);
      expect(removeCommands.some(c => c!.includes('worktree-lifecycle-logger'))).toBe(true);
    });
  });

  // ===========================================================================
  // Entry point exports match hooks.json
  //
  // These two tests import compiled entry bundles (~80-100KB each with
  // transitive deps). Cold-import under vitest parallel workers is ~1.5s
  // in isolation but can exceed the 5s default when CPU is saturated by
  // sibling test files. Raise the timeout to 15s so parallel runs don't
  // flake — the tests themselves are trivially fast once the import
  // completes.
  // ===========================================================================
  describe('entry point bundle exports', () => {
    it('stop bundle exports stop-failure-handler', { timeout: 15000 }, async () => {
      const stopBundle = await import('../../entries/stop.js');
      expect(stopBundle.hooks['stop/stop-failure-handler']).toBeDefined();
      expect(typeof stopBundle.hooks['stop/stop-failure-handler']).toBe('function');
    });

    it('lifecycle bundle exports worktree-lifecycle-logger', { timeout: 15000 }, async () => {
      const lifecycleBundle = await import('../../entries/lifecycle.js');
      expect(lifecycleBundle.hooks['worktree/worktree-lifecycle-logger']).toBeDefined();
      expect(typeof lifecycleBundle.hooks['worktree/worktree-lifecycle-logger']).toBe('function');
    });
  });

  // ===========================================================================
  // Stop event error-loop safety constraints
  // ===========================================================================
  describe('Stop / StopFailure error-loop safety', () => {
    it('Stop event uses async mode (fire-and-forget)', () => {
      const hooks = hooksConfig.hooks.Stop?.flatMap(g => g.hooks ?? []) ?? [];
      const asyncHooks = hooks.filter(h => h.async === true);
      expect(asyncHooks.length).toBeGreaterThan(0);
    });

    it('all StopFailure hooks are async (error-loop safety critical)', () => {
      const hooks = hooksConfig.hooks.StopFailure?.flatMap(g => g.hooks ?? []) ?? [];
      for (const hook of hooks) {
        // StopFailure fires ON API errors — sync hooks here could re-trigger the error loop
        expect(hook.async, 'StopFailure hook must be async').toBe(true);
      }
    });
  });

  // ===========================================================================
  // hooks.json description accuracy
  // ===========================================================================
  describe('hooks.json description accuracy', () => {
    it('description total matches 188', () => {
      // 184 -> 186: M126 #1543 — posttool/secret-handler + (intermediate bumps)
      // 186 -> 187: M130 #1487 — lifecycle/cc-version-check
      // 187 -> 188: ASCII Design System — posttool/ascii-lint
      expect(hooksConfig.description).toContain('188 total');
    });

    it('description counts add up (global + agent + skill = total)', () => {
      const match = hooksConfig.description.match(/(\d+) global \+ (\d+) agent-scoped \+ (\d+) skill-scoped = (\d+) total/);
      expect(match).not.toBeNull();
      if (match) {
        const [, global, agent, skill, total] = match.map(Number);
        expect(global + agent + skill).toBe(total);
      }
    });
  });
});
